/* selectMlocmaList */ SELECT CONCAT(ML.WAREKEY, ML.AREAKEY, ML.LOCAKEY) AS ROWKEY , ML.WAREKEY, ML.AREAKEY , MA.AREANAM AS AREANAM, ML.LOCAKEY , ML.LOCANAM, ML.LOCSTAT, ML.LOCTYPE, ML.LOCMEMO, ML.LOCWIDT , ML.LOCLENG, ML.LOCHEIG, ML.LOCCUBI, ML.SIZEPRI, ML.BTRCPRI , ML.ITDTPRI, ML.CUSTPRI, ML.REGIPRI, ML.DESTPRI, ML.INBOPRI , ML.OUBOPRI, ML.LOUSEYN, ML.UPDTCHK , DATE_FORMAT(ML.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(ML.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(ML.CREUSER) AS CREUSER , DATE_FORMAT(ML.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(ML.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(ML.LMOUSER) AS LMOUSER FROM ${userData.schema}.MLOCMA ML INNER JOIN ${userData.schema}.MAREMA MA ON ML.WAREKEY = MA.WAREKEY AND ML.AREAKEY = MA.AREAKEY
AND ML.WAREKEY = #{params.warekey}
AND ML.AREAKEY = #{params.areakey}
AND UPPER(MA.AREANAM) LIKE CONCAT('%', UPPER(#{params.areanam}), '%')
AND UPPER(ML.LOCAKEY) LIKE CONCAT('%', UPPER(#{params.locakey}), '%')
AND UPPER(ML.LOCANAM) LIKE CONCAT('%', UPPER(#{params.locanam}), '%')
