/* selectMlocmaSelectBox */
SELECT LOCAKEY AS COMBOVL, LOCANAM AS COMBONM
FROM ${userData.schema}.MLOCMA
WHERE LOUSEYN = 'Y'

   AND WAREKEY = #{params.warekey}


   AND AREAKEY = #{params.areakey}


