GROUP BY LOCANAM, LOCAKEY
ORDER BY LOCANAM, LOCAKEY

   	  SELECT ML.LOCTYPE FROM ${userData.schema}.MLOCMA ML


	         AND ML.WAREKEY = #{params.warekey}


	         AND ML.LOCAKEY = #{params.locakey}

	  /* selectWareAreaRelations */
   SELECT MWA.WAREKEY AS WAREKEY, MAR.AREAKEY AS AREAKEY
   	   , MAR.AREANAM AS AREANAM, CONCAT('[', MAR.AREAKEY, '] ', MAR.AREANAM) AS combonm
   FROM ${userData.schema}.MWARMA MWA
   INNER JOIN ${userData.schema}.MAREMA MAR ON (MWA.WAREKEY = MAR.WAREKEY)
   WHERE MWA.WHUSEYN = 'Y' AND MAR.ARUSEYN = 'Y'

      AND MWA.WAREKEY = #{params.warekey}


      AND MAR.AREAKEY = #{params.areakey}

   GROUP BY MWA.WAREKEY, MAR.AREAKEY, MAR.AREANAM
   ORDER BY MWA.WAREKEY, MAR.AREAKEY

/* selectWareAreaLocRelations */ SELECT MWA.WAREKEY AS WAREKEY, MAR.AREAKEY AS AREAKEY , MAR.AREANAM AS AREANAM, MLO.LOCAKEY AS LOCAKEY, MLO.LOCANAM AS LOCANAM , MLO.LOCTYPE FROM ${userData.schema}.MWARMA MWA INNER JOIN ${userData.schema}.MAREMA MAR ON (MWA.WAREKEY = MAR.WAREKEY) INNER JOIN ${userData.schema}.MLOCMA MLO ON (MWA.WAREKEY = MLO.WAREKEY AND MAR.AREAKEY = MLO.AREAKEY) WHERE MWA.WHUSEYN = 'Y' AND MAR.ARUSEYN = 'Y' AND MLO.LOUSEYN = 'Y'
AND MWA.WAREKEY = #{params.warekey}
AND MAR.AREAKEY = #{params.areakey}
AND MLO.LOCTYPE IN
#{loctype}
GROUP BY MWA.WAREKEY, MAR.AREAKEY, MLO.LOCAKEY, MAR.AREANAM, MLO.LOCANAM ORDER BY MWA.WAREKEY, MAR.AREAKEY, MLO.LOCAKEY

/* selectLocationRelationList */ SELECT MLO.WAREKEY, MLO.AREAKEY, MLO.LOCAKEY, MLO.LOCANAM, MLO.LOCTYPE FROM ${userData.schema}.MLOCMA MLO INNER JOIN ${userData.schema}.MWARMA MWA ON (MWA.WAREKEY = MLO.WAREKEY) INNER JOIN ${userData.schema}.MAREMA MAR ON ( MAR.WAREKEY = MWA.WAREKEY AND MAR.WAREKEY = MLO.WAREKEY AND MAR.AREAKEY = MLO.AREAKEY ) WHERE MWA.WHUSEYN = 'Y' AND MAR.ARUSEYN = 'Y' AND MLO.LOUSEYN = 'Y' AND MLO.LOCSTAT = 'NORMAL'
AND MLO.WAREKEY = #{param.warekey}
AND MLO.LOCTYPE = #{param.loctype}

/* selectMequemaList */ SELECT CONCAT(ME.WAREKEY, ME.AREAKEY, ME.EQUIPKY) AS ROWKEY , ME.WAREKEY, ME.AREAKEY, MA.AREANAM AS AREANAM , ME.EQUIPKY, ME.EQUINAM, ME.EQUTYPE, ME.EQUMEMO, ME.EQUVEND , DATE_FORMAT(ME.EQUPURD,'%Y-%m-%d') AS EQUPURD, ME.EQUSTAT , ME.EQMANNM, ME.EQMANTL, ME.EQMANEM, ME.EQUWIDT, ME.EQULENG , ME.EQUHEIG, ME.EQUWEIG, ME.EQMAXWG, ME.EQUSEYN, ME.UPDTCHK , DATE_FORMAT(ME.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(ME.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(ME.CREUSER) AS CREUSER , DATE_FORMAT(ME.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(ME.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(ME.LMOUSER) AS LMOUSER FROM ${userData.schema}.MEQUMA ME INNER JOIN ${userData.schema}.MAREMA MA ON ME.WAREKEY = MA.WAREKEY AND ME.AREAKEY = MA.AREAKEY
AND ME.WAREKEY = #{params.warekey}
AND ME.AREAKEY = #{params.areakey}
AND UPPER(MA.AREANAM) LIKE CONCAT('%', UPPER(#{params.areanam}), '%')
AND ME.EQUIPKY LIKE CONCAT('%', UPPER(#{params.equipky}), '%')
AND UPPER(ME.EQUINAM) LIKE CONCAT('%', UPPER(#{params.equinam}), '%')
AND ME.EQUSEYN = #{params.equseyn}
AND ME.EQUTYPE = #{params.equtype}
AND ME.EQUSTAT = #{params.equstat}
ORDER BY MA.AREANAM, ME.EQUINAM, ME.EQUIPKY

