mapper.select:
/* selectMequmaSelectBox */
SELECT EQUIPKY AS COMBOVL, EQUINAM AS COMBONM
FROM ${userData.schema}.MEQUMA
WHERE EQUSEYN = 'Y'

   AND WAREKEY = #{params.warekey}


   AND AREAKEY = #{params.areakey}


   AND EQUIPKY = #{params.equipky}


   AND EQUTYPE = #{params.equtype}


   AND EQUSTAT = #{params.equstat}

GROUP BY EQUINAM, EQUIPKY
ORDER BY EQUINAM, EQUIPKY

/* selectWareAreaEquipRelations */ SELECT MW.WAREKEY AS WAREKEY, MA.AREAKEY AS AREAKEY , MA.AREANAM AS AREANAM, ME.EQUIPKY AS EQUIPKY, ME.EQUINAM AS EQUINAM FROM ${userData.schema}.MWARMA MW INNER JOIN ${userData.schema}.MAREMA MA ON (MW.WAREKEY = MA.WAREKEY) INNER JOIN ${userData.schema}.MEQUMA ME ON (MA.WAREKEY = ME.WAREKEY AND MA.AREAKEY = ME.AREAKEY) WHERE MW.WHUSEYN = 'Y' AND MA.ARUSEYN = 'Y' AND ME.EQUSEYN = 'Y'
AND MW.WAREKEY = #{params.warekey}
AND MA.AREAKEY = #{params.areakey}
GROUP BY MW.WAREKEY, MA.AREAKEY, ME.EQUIPKY, MA.AREANAM, ME.EQUINAM ORDER BY MW.WAREKEY, MA.AREAKEY, ME.EQUIPKY

/* selectMlocmaForMapping */ SELECT CONCAT(ML.WAREKEY, ML.AREAKEY, ML.LOCAKEY) AS ROWKEY , ML.WAREKEY, ML.AREAKEY, ML.LOCAKEY, ML.LOCANAM, ML.LOCSTAT , ML.LOCTYPE, ML.LOCMEMO, ML.LOCWIDT, ML.LOCLENG, ML.LOCHEIG , ML.LOCCUBI, ML.SIZEPRI, ML.BTRCPRI, ML.ITDTPRI, ML.CUSTPRI , ML.REGIPRI, ML.DESTPRI, ML.INBOPRI, ML.OUBOPRI, ML.LOUSEYN , MEL.UPDTCHK, MEL.MANEQYN, MEL.ELUSEYN, ME.EQUIPKY, MC.COMCDTX , ME.EQUINAM , ML.UPDTCHK AS UPDTCHK2 , DATE_FORMAT(ML.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(ML.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(ML.CREUSER) AS CREUSER , DATE_FORMAT(ML.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(ML.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(ML.LMOUSER) AS LMOUSER FROM ${userData.schema}.MLOCMA ML LEFT JOIN ${userData.schema}.MEQUMA ME ON ML.WAREKEY = ME.WAREKEY AND ML.AREAKEY = ME.AREAKEY LEFT JOIN ${userData.schema}.MEQLOC MEL ON ML.WAREKEY = MEL.WAREKEY AND ML.AREAKEY = MEL.AREAKEY AND ME.EQUIPKY = MEL.EQUIPKY AND ML.LOCAKEY = MEL.LOCAKEY INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDKY = 'LOCTYPE' AND MC.COMCDVL = ML.LOCTYPE AND MC.COUSEYN = 'Y' WHERE ML.LOUSEYN = 'Y'
AND ML.WAREKEY = #{params.warekey}
AND ML.AREAKEY = #{params.areakey}
AND ME.EQUIPKY = #{params.equipky}
ORDER BY ML.LOCANAM, ML.LOCAKEY, MEL.EQUIPKY

   		/* selectMeqlocCnt */
