WHERE LOCAKEY = #{locakey}

mapper.select:
/* selectEquipkyByLoc */ SELECT GROUP_CONCAT(MQ.EQUIPKY ORDER BY MQ.MANEQYN DESC SEPARATOR ',') AS EQUIPKY FROM ${userData.schema}.MEQLOC MQ INNER JOIN ${userData.schema}.MLOCMA ML ON ML.WAREKEY = MQ.WAREKEY AND ML.AREAKEY = MQ.AREAKEY AND ML.LOCAKEY = MQ.LOCAKEY AND ML.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MEQUMA ME ON ME.WAREKEY = MQ.WAREKEY AND ME.AREAKEY = MQ.AREAKEY AND ME.EQUIPKY = MQ.EQUIPKY AND ME.EQUSTAT = 'NORMAL' WHERE MQ.ELUSEYN = 'Y'
AND MQ.WAREKEY = #{param.warekey}
AND MQ.AREAKEY = #{param.areakey}
AND MQ.LOCAKEY = #{param.locakey}
ORDER BY MQ.MANEQYN DESC

/* selectEquipByLocForSelectBox */ SELECT MQ.WAREKEY, MQ.AREAKEY, MQ.LOCAKEY, MQ.EQUIPKY , ML.LOCTYPE, ML.LOCANAM, EQ.EQUINAM FROM ${userData.schema}.MEQLOC MQ INNER JOIN ${userData.schema}.MLOCMA ML ON ML.WAREKEY = MQ.WAREKEY AND ML.AREAKEY = MQ.AREAKEY AND ML.LOCAKEY = MQ.LOCAKEY INNER JOIN ${userData.schema}.MEQUMA EQ ON EQ.WAREKEY = MQ.WAREKEY AND EQ.AREAKEY = MQ.AREAKEY AND EQ.EQUIPKY = MQ.EQUIPKY WHERE MQ.ELUSEYN = 'Y' AND EQ.EQUSTAT = 'NORMAL'
AND MQ.WAREKEY = #{param.warekey}
AND MQ.AREAKEY = #{param.areakey}
AND MQ.LOCAKEY = #{param.locakey}
AND ML.LOCTYPE = #{param.loctype}
ORDER BY ML.LOCANAM
